import sys
class Solution:
    def longestPath(self, parent, s):
        n = len(parent)
        children = [[] for _ in range(n)]
        for i in range(1, n):
            children[parent[i]].append(i)
        sys.setrecursionlimit(300000)
        best = [0]
        # returns longest downward chain (in nodes) starting at node using valid edges
        def dfs(u):
            top1 = top2 = 0
            for c in children[u]:
                cl = dfs(c)
                if s[c] != s[u]:
                    if cl > top1:
                        top2 = top1
                        top1 = cl
                    elif cl > top2:
                        top2 = cl
            best[0] = max(best[0], 1 + top1 + top2)
            return 1 + top1
        # iterative to avoid deep recursion on skewed trees
        order = []
        stack = [0]
        visited = [False] * n
        while stack:
            u = stack.pop()
            order.append(u)
            for c in children[u]:
                stack.append(c)
        down = [0] * n
        for u in reversed(order):
            top1 = top2 = 0
            for c in children[u]:
                if s[c] != s[u]:
                    cl = down[c]
                    if cl > top1:
                        top2 = top1
                        top1 = cl
                    elif cl > top2:
                        top2 = cl
            best[0] = max(best[0], 1 + top1 + top2)
            down[u] = 1 + top1
        return best[0]

