var longestPath = function(parent, s) {
    const n = parent.length;
    const children = Array.from({ length: n }, () => []);
    for (let i = 1; i < n; i++) children[parent[i]].push(i);
    const order = [];
    const stack = [0];
    while (stack.length) {
        const u = stack.pop();
        order.push(u);
        for (const c of children[u]) stack.push(c);
    }
    const down = new Array(n).fill(1);
    let ans = 1;
    for (let k = order.length - 1; k >= 0; k--) {
        const u = order[k];
        let best1 = 0, best2 = 0;
        for (const c of children[u]) {
            if (s[c] !== s[u]) {
                const d = down[c];
                if (d > best1) { best2 = best1; best1 = d; }
                else if (d > best2) { best2 = d; }
            }
        }
        ans = Math.max(ans, 1 + best1 + best2);
        down[u] = 1 + best1;
    }
    return ans;
};
